-- copy the same STAT orders to shifts 203–207 so every shift has demo data
insert into stat_orders (id, shift_id, admission_id, title, kind, ordered_by, ordered_at_display, reason, severity)
select
  gen_random_uuid(),
  s.shift_id,
  so.admission_id,
  so.title,
  so.kind,
  so.ordered_by,
  so.ordered_at_display,
  so.reason,
  so.severity
from stat_orders so
cross join (values
  ('00000000-0000-0000-0000-000000000203'::uuid),
  ('00000000-0000-0000-0000-000000000204'::uuid),
  ('00000000-0000-0000-0000-000000000205'::uuid),
  ('00000000-0000-0000-0000-000000000206'::uuid),
  ('00000000-0000-0000-0000-000000000207'::uuid)
) as s(shift_id)
where so.shift_id = '00000000-0000-0000-0000-000000000202';
